import React from "react";
import {
  Box,
  Stack,
  Typography,
  IconButton,
  Chip,
  Button,
  useTheme,
  alpha,
} from "@mui/material";
import {
  PlayArrow,
  OpenInNew,
  GitHub,
  Code,
  Visibility,
} from "@mui/icons-material";
import { useNavigate } from "react-router-dom";
export default function LiveProjectCard({
  project,
  idx,
  isPlaying,
  setIsPlaying,
  Pause,
}) {
  const navigate = useNavigate();
  const theme = useTheme();
  return (
    <Stack
      key={idx}
      className={`project-${idx}`}
      sx={{
        minWidth: "100vw",
        height: "100vh",
        position: "relative",
        padding: { xs: 2, md: 8 },
      }}
    >
      <Stack
        sx={{
          height: "100%",
          display: "grid",
          gridTemplateColumns: { xs: "1fr", lg: "1fr 1fr" },
          gap: 6,
          alignItems: "center",
        }}
      >
        {/* Media & Stats */}
        <Stack
          onClick={() => navigate(`/projects/details/${project?._id}`)}
          sx={{ height: "100%", gap: 3, width: "100%" }}
        >
          <Box
            className="reveal-item"
            sx={{
              flex: 1,
              borderRadius: 4,
              overflow: "hidden",
              position: "relative",
              boxShadow: `0 20px 60px ${alpha(project.color, 0.3)}`,
              border: `1px solid ${alpha(project.color, 0.2)}`,
              padding: "1rem",
            }}
          >
            <Box
              component="img"
              src={project.image}
              // autoPlay
              // loop
              // muted={true}
              // playsInline
              sx={{
                width: "100%",
                height: "100%",
                objectFit: "cover",
                borderRadius: "16px",
              }}
            />
            <Chip
              icon={<Visibility />}
              label="LIVE NOW"
              sx={{
                position: "absolute",
                top: 16,
                right: 16,
                background: alpha("#FF4757", 0.9),
                color: "white",
                fontWeight: "bold",
                backdropFilter: "blur(10px)",
                animation: "pulse 2s infinite",
              }}
            />
          </Box>
        </Stack>

        {/* Details Column */}
        <Stack
          className="reveal-item"
          sx={{ gap: 4, width: "100%", overflow: "hidden" }}
        >
          <Stack gap={2}>
            <Chip
              label={`0${idx + 1}`}
              sx={{
                width: "fit-content",
                background: alpha(project.color, 0.2),
                color: project.color,
                fontWeight: "bold",
              }}
            />
            <Typography
              variant="h1"
              sx={{
                fontSize: { xs: "2.5rem", md: "3rem" },
                fontWeight: 900,
                background: `linear-gradient(135deg, ${project.color}, ${theme.palette.primary.light})`,
                backgroundClip: "text",
                WebkitTextFillColor: "transparent",
                lineHeight: 1.1,
              }}
            >
              {project.title}
            </Typography>
            <Typography
              variant="body1"
              sx={{ fontSize: "1rem", lineHeight: 1.8, opacity: 0.9 }}
            >
              {project.description}
            </Typography>
          </Stack>

          {/* Links */}
          <Stack direction="row" gap={2}>
            <Button
              variant="contained"
              href={project.liveUrl}
              target="_blank"
              startIcon={<OpenInNew />}
              sx={{
                background: `linear-gradient(135deg, ${project.color}, ${alpha(
                  project.color,
                  0.8,
                )})`,
                "&:hover": {
                  background: `linear-gradient(135deg, ${alpha(
                    project.color,
                    0.9,
                  )}, ${alpha(project.color, 0.7)})`,
                  transform: "translateY(-2px)",
                  boxShadow: `0 10px 30px ${alpha(project.color, 0.4)}`,
                },
              }}
            >
              Visit Live Site
            </Button>
            <Button
              variant="outlined"
              href={project.githubUrl}
              target="_blank"
              startIcon={<GitHub />}
              sx={{
                borderColor: alpha(project.color, 0.3),
                color: project.color,
                "&:hover": {
                  borderColor: project.color,
                  background: alpha(project.color, 0.1),
                },
              }}
            >
              View Code
            </Button>
          </Stack>

          {/* Features */}
          <Stack gap={2} sx={{ width: "100%" }}>
            <Typography variant="h6" sx={{ opacity: 0.7 }}>
              Key Features
            </Typography>
            <Stack gap={1} sx={{ width: "100%" }}>
              {project?.keyFeatures?.map((feature, i) => (
                <Stack
                  key={i}
                  direction="row"
                  alignItems="center"
                  gap={1}
                  sx={{ width: "100%", overflow: "hidden" }}
                >
                  <Box
                    sx={{
                      width: 8,
                      height: 8,
                      borderRadius: "50%",
                      background: project.color,
                      animation: `pulse 2s infinite ${i * 0.2}s`,
                    }}
                  />
                  <Typography
                    sx={{
                      whiteSpace: "nowrap",
                      textOverflow: "ellipsis",
                      overflow: "hidden",
                      // width:"100%"
                    }}
                    variant="body2"
                  >
                    {feature}
                  </Typography>
                </Stack>
              ))}
            </Stack>
          </Stack>
        </Stack>
      </Stack>

      {/* Floating Elements */}
      {[1, 2, 3].map((i) => (
        <Box
          key={i}
          className="floating-element"
          sx={{
            position: "absolute",
            width: 100 + i * 50,
            height: 100 + i * 50,
            borderRadius: "50%",
            background: `radial-gradient(circle, ${alpha(
              project.color,
              0.1,
            )} 0%, transparent 70%)`,
            top: `${i * 20}%`,
            left: `${i * 10}%`,
            zIndex: -1,
          }}
        />
      ))}
    </Stack>
  );
}
