import {
  Box,
  Stack,
  Typography,
  Button,
  useTheme,
  useMediaQuery,
} from "@mui/material";
import React, { useEffect, useState } from "react";
import { useTranslation } from "react-i18next";
import { useLanguageStore } from "../../../../Store/store";
import HeroContent from "./HeroContent";
import HeroPicture from "./HeroPicture";

export default function Hero() {
  const { t } = useTranslation();
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down("lg"));
  const { language } = useLanguageStore();
  // 3D image
  const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 });

  useEffect(() => {
    const handleMouseMove = (e) => {
      setMousePosition({
        x: (e.clientX / window.innerWidth - 0.5) * 20,
        y: (e.clientY / window.innerHeight - 0.5) * 20,
      });
    };

    window.addEventListener("mousemove", handleMouseMove);
    return () => window.removeEventListener("mousemove", handleMouseMove);
  }, []);

  return (
    <Stack
    id="home-section"
      sx={{
        height: "100vh",
        position: "relative",
        overflow: "hidden",
        background: `
          radial-gradient(circle at 20% 50%, ${theme.palette.primary.dark}20 0%, transparent 40%),
          radial-gradient(circle at 80% 20%, ${theme.palette.secondary.dark}15 0%, transparent 40%),
          linear-gradient(135deg, ${theme.palette.background.default} 0%, ${theme.palette.background.lightBlue} 100%)
        `,
        display: "flex",
        flexDirection: isMobile ? "column-reverse" : "row",
        alignItems: "center",
        justifyContent: "center",
        padding: theme.spacing(4),
        gap: theme.spacing(8),
      }}
    >
      {/* Particles Background */}
      <Box
        sx={{
          position: "absolute",
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          backgroundImage: `
          radial-gradient(circle at 1px 1px, ${theme.palette.primary.light}10 1px, transparent 0)
        `,
          backgroundSize: "50px 50px",
          opacity: 0.3,
        }}
      />

      {/* Animated Gradient Orbs */}
      <Box
        sx={{
          position: "absolute",
          width: "500px",
          height: "500px",
          borderRadius: "50%",
          background: `radial-gradient(circle, ${theme.palette.primary.main}30 0%, transparent 70%)`,
          top: "-200px",
          right: "-200px",
          animation: "float 20s ease-in-out infinite",
          filter: "blur(40px)",
          "@keyframes float": {
            "0%, 100%": { transform: "translate(0, 0)" },
            "50%": { transform: "translate(-50px, 50px)" },
          },
        }}
      />

      {/* Image Container with 3D effect */}
      <HeroPicture mousePosition={mousePosition} />
      {/* Content Stack */}
      <HeroContent />
      {/* Scroll Indicator */}
      <Box
        sx={{
          position: "absolute",
          bottom: "40px",
          left: "50%",
          transform: "translateX(-50%)",
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          gap: 1,
          opacity: 0.7,
          animation: "bounce 2s infinite",
          "@keyframes bounce": {
            "0%, 100%": { transform: "translateX(-50%) translateY(0)" },
            "50%": { transform: "translateX(-50%) translateY(-10px)" },
          },
        }}
      >
        <Typography
          variant="caption"
          sx={{ color: theme.palette.text.secondary }}
        >
          Scroll
        </Typography>
        <Box
          sx={{
            width: "24px",
            height: "40px",
            borderRadius: "12px",
            border: `2px solid ${theme.palette.primary.main}`,
            position: "relative",
            "&::before": {
              content: '""',
              position: "absolute",
              top: "8px",
              left: "50%",
              transform: "translateX(-50%)",
              width: "4px",
              height: "8px",
              borderRadius: "2px",
              backgroundColor: theme.palette.primary.main,
              animation: "scroll 2s infinite",
            },
            "@keyframes scroll": {
              "0%": {
                opacity: 1,
                transform: "translateX(-50%) translateY(0)",
              },
              "100%": {
                opacity: 0,
                transform: "translateX(-50%) translateY(20px)",
              },
            },
          }}
        />
      </Box>
    </Stack>
  );
}
