import { Box, Stack, Typography, useTheme } from "@mui/material";
import { useNavigate } from "react-router-dom";
import { motion } from "framer-motion";
import { alpha } from "@mui/material/styles";

export default function ProjectCard({ e }) {
  const theme = useTheme();
  const navigate = useNavigate();

  return (
    <motion.div
      initial={{ opacity: 0, y: 30 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true }}
      transition={{ duration: 0.4 }}
      style={{ height: "100%", width: "100%" }}
    >
      <Box
        onClick={() => navigate(`details/${e?._id}`)}
        sx={{
          position: "relative",
          width: "100%",
          height: "100%",
          borderRadius: "20px",
          overflow: "hidden",
          cursor: "pointer",
          border: `2px solid ${alpha(theme.palette.primary.main, 0.3)}`,
          transition: "all 0.4s cubic-bezier(0.2, 0.9, 0.4, 1.1)",
          "&:hover": {
            border: `2px solid ${theme.palette.secondary.main}`,
            transform: "translateY(-6px)",
            boxShadow: `0 20px 30px -15px ${alpha(theme.palette.secondary.main, 0.3)}`,
            "& .main-image": {
              transform: "scale(1.05)",
            },
            "& .hiddenItem": {
              visibility: "visible",
              opacity: 1,
            },
          },
        }}
      >
        {/* Main Image */}
        <Box
          className="main-image"
          sx={{
            width: "100%",
            height: "100%",
            transition: "transform 0.5s ease",
          }}
        >
          <img
            style={{
              width: "100%",
              height: "100%",
              objectFit: "cover",
            }}
            src={e?.image}
            alt={e?.title}
          />
        </Box>

        {/* Hidden Items - Blur Image on Hover */}
        <Stack
          className="hiddenItem"
          sx={{
            position: "absolute",
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            visibility: "hidden",
            opacity: 0,
            transition: "all 0.4s cubic-bezier(0.2, 0.9, 0.4, 1.1)",
            justifyContent: "flex-end",
          }}
        >
          {/* Blur Background Image */}
          <Box
            sx={{
              position: "absolute",
              top: 0,
              left: 0,
              right: 0,
              bottom: 0,
              filter: "blur(6px)",
              transform: "scale(1.1)",
            }}
          >
            <img
              style={{
                width: "100%",
                height: "100%",
                objectFit: "cover",
              }}
              src={e?.images?.[1] || e?.image}
              alt={e?.title}
            />
          </Box>

          {/* Dark Overlay for better text readability */}
          <Box
            sx={{
              position: "absolute",
              top: 0,
              left: 0,
              right: 0,
              bottom: 0,
              background: `linear-gradient(to top, ${alpha(theme.palette.background.default, 0.9)} 0%, ${alpha(theme.palette.primary.dark, 0.4)} 100%)`,
            }}
          />

          {/* Title */}
          <Typography
            sx={{
              position: "relative",
              zIndex: 2,
              bottom: { xs: "1rem", sm: "1.5rem", md: "2rem" },
              left: { xs: "1rem", sm: "1.5rem", md: "2rem" },
              color: "white",
              fontWeight: "bold",
              fontSize: { xs: "1rem", sm: "1.2rem", md: "1.3rem" },
              textShadow: "0 2px 10px rgba(0,0,0,0.5)",
              letterSpacing: "-0.3px",
              maxWidth: "80%",
            }}
          >
            {e?.title}
          </Typography>

          {/* Optional: Small indicator */}
          <Box
            sx={{
              position: "relative",
              zIndex: 2,
              bottom: { xs: "0.8rem", sm: "1.2rem", md: "1.5rem" },
              left: { xs: "1rem", sm: "1.5rem", md: "2rem" },
              width: "30px",
              height: "2px",
              background: theme.palette.secondary.main,
              borderRadius: "2px",
            }}
          />
        </Stack>
      </Box>
    </motion.div>
  );
}