import { useLayoutEffect, useRef, useState, useEffect } from "react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { Box, Button, Stack, useTheme } from "@mui/material";
import { OpenInNew, Pause } from "@mui/icons-material";
import LiveProjectCard from "./LiveProjectCard";
import { useNavigate } from "react-router-dom";
import { liveProjectsData as livePrData } from "../../../../Data/liveProjects";

gsap.registerPlugin(ScrollTrigger);

export default function LiveProjects() {
  const theme = useTheme();
  const navigate = useNavigate();
  const sectionRef = useRef(null);
  const trackRef = useRef(null);

  const [sectionHeight, setSectionHeight] = useState("100vh");
  const [isPlaying, setIsPlaying] = useState(true);

  const liveProjectsData = livePrData?.slice(0, 4);
  useLayoutEffect(() => {
    const updateHeight = () => {
      if (!trackRef.current) return;

      const scrollDistance = trackRef.current.scrollWidth - window.innerWidth;
      // height = scrollDistance + viewportHeight
      setSectionHeight(scrollDistance + window.innerHeight);
      ScrollTrigger.refresh();
    };

    updateHeight();
    window.addEventListener("resize", updateHeight);

    return () => window.removeEventListener("resize", updateHeight);
  }, []);

  useLayoutEffect(() => {
    const ctx = gsap.context(() => {
      gsap.to(trackRef.current, {
        x: () => -(trackRef.current.scrollWidth - window.innerWidth),
        ease: "none",
        scrollTrigger: {
          trigger: sectionRef.current,
          start: "top top",
          end: () => `+=${trackRef.current.scrollWidth - window.innerWidth}`,
          pin: true,
          scrub: 1.5,
          anticipatePin: 1,
          invalidateOnRefresh: true,
          onLeave: () => {
            setSectionHeight("100vh !important");
          },

          onEnterBack: () => {
            const scrollDistance =
              trackRef.current.scrollWidth - window.innerWidth;
            setSectionHeight(scrollDistance + window.innerHeight);
          },
        },
      });
    }, sectionRef);

    return () => ctx.revert();
  }, [liveProjectsData.length]);

  const items = liveProjectsData.map((project, idx) => (
    <LiveProjectCard
      key={idx}
      idx={idx}
      project={project}
      isPlaying={isPlaying}
      setIsPlaying={setIsPlaying}
      Pause={Pause}
    />
  ));
  return (
    <Box
      id="projects-section"
      ref={sectionRef}
      component="section"
      sx={{
        height: sectionHeight,
        overflow: "hidden",
        position: "relative",
        pt: "2rem",
      }}
    >
      {/* See All  */}
      <Button
        onClick={() => navigate("/projects")}
        startIcon={<OpenInNew />}
        color="secondary"
        variant="outlined"
        sx={{
          position: "absolute",
          zIndex: "10",
          left: "50%",
          transform: "translateX(-50%)",
          transition: "all .3s",
          // border:`1px solid ${theme.palette.primary.dar}` ,
          ":hover": {
            scale: "1.02",
          },
        }}
      >
        See All Projects
        {/* <ArrowBackIosOutlined/> */}
      </Button>
      {/* Background */}
      <Box
        sx={{
          position: "absolute",
          inset: 0,
          opacity: 0.03,
          pointerEvents: "none",
        }}
      />

      {/* Horizontal Track */}
      <Stack
        ref={trackRef}
        direction="row"
        sx={{
          height: "100vh",
          width: "fit-content",
        }}
      >
        {items}
      </Stack>
    </Box>
  );
}
