import {
  Container,
  Stack,
  Typography,
  useTheme,
  Box,
  IconButton,
  Paper,
} from "@mui/material";
import LinkedInIcon from "@mui/icons-material/LinkedIn";
import GitHubIcon from "@mui/icons-material/GitHub";
import { Instagram } from "@mui/icons-material";
import EmailIcon from "@mui/icons-material/Email";
import PhoneIcon from "@mui/icons-material/Phone";
import LocationOnIcon from "@mui/icons-material/LocationOn";
import TelegramIcon from "@mui/icons-material/Telegram";

export default function ContactMe() {
  const theme = useTheme();

  // Social links
  const socialLinks = [
    {
      icon: <LinkedInIcon fontSize="large" />,
      label: "LinkedIn",
      color: theme.palette.primary.main,
      url: "https://linkedin.com/in/pouriya-3a",
    },
    {
      icon: <GitHubIcon fontSize="large" />,
      label: "GitHub",
      color: theme.palette.text.secondary,
      url: "https://github.com/pouriya-3a",
    },
    {
      icon: <Instagram fontSize="large" />,
      label: "GitHub",
      color: theme.palette.info.main,
      url: "https://instagram.com/pouriya-3a",
    },
    {
      icon: <TelegramIcon fontSize="large" />,
      label: "Telegram",
      color: theme.palette.secondary.main,
      url: "https://t.me/pouriya_3a",
    },
    {
      icon: <EmailIcon fontSize="large" />,
      label: "Email",
      color: theme.palette.success.main,
      url: "mailto:pouriyasabouri1385@gmail.com",
    },
  ];

  // Contact info
  const contactInfo = [
    {
      icon: <EmailIcon />,
      title: "Email",
      value: "pouriyasabouri1385@gmail.com",
      color: theme.palette.primary.light,
    },
    {
      icon: <PhoneIcon />,
      title: "Phone",
      value: "+98 915 686 2623",
      color: theme.palette.secondary.light,
    },
    {
      icon: <LocationOnIcon />,
      title: "Location",
      value: "Iran , Khorasan Razavi , Mashhad",
      color: theme.palette.info.light,
    },
  ];

  const handleSocialClick = (url) => {
    window.open(url, "_blank");
  };

  const contactItems = contactInfo.map((item, index) => (
    <Box
      key={index}
      sx={{
        display: "flex",
        alignItems: "center",
        gap: 2,
        p: 2,
        borderRadius: "12px",
        bgcolor: theme.palette.background.lightBlue,
        border: `1px solid ${theme.palette.divider}`,
        transition: "all 0.3s ease",
        width: "100%",
        "&:hover": {
          //   transform: "translateX(8px)",
          borderColor: item.color,
        },
      }}
    >
      <Box
        sx={{
          p: 1.5,
          borderRadius: "10px",
          bgcolor: `${item.color}20`,
          color: item.color,
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
        }}
      >
        {item.icon}
      </Box>
      <Box>
        <Typography
          variant="body2"
          sx={{ color: theme.palette.text.secondary }}
        >
          {item.title}
        </Typography>
        <Typography
          variant="body1"
          sx={{
            color: theme.palette.text.primary,
            fontWeight: 500,
            fontSize:".8rem"
          }}
        >
          {item.value}
        </Typography>
      </Box>
    </Box>
  ));
  const socialItems = socialLinks?.map((social, index) => (
    <IconButton
      key={index}
      onClick={() => handleSocialClick(social.url)}
      sx={{
        width: 56,
        height: 56,
        bgcolor: theme.palette.background.paper,
        border: `2px solid ${social.color}40`,
        color: social.color,
        transition: "all 0.3s ease",
        "&:hover": {
          bgcolor: `${social.color}15`,
          transform: "translateY(-4px)",
          borderColor: social.color,
        },
      }}
      aria-label={social.label}
    >
      {social.icon}
    </IconButton>
  ));
  return (
    <Box
      id="contact-section"
      sx={{
        py: 8,
        px: 2,
        background: `
          radial-gradient(circle at 20% 50%, ${theme.palette.primary.dark}20 0%, transparent 40%),
          radial-gradient(circle at 80% 20%, ${theme.palette.secondary.dark}15 0%, transparent 40%),
          linear-gradient(135deg, ${theme.palette.background.default} 0%, ${theme.palette.background.lightBlue} 100%)
        `,
      }}
    >
      <Container maxWidth="lg">
        {/* Title Section */}
        <Box textAlign="center" mb={6}>
          <Typography
            variant="h3"
            sx={{
              color: theme.palette.primary.light,
              fontWeight: 700,
              mb: 2,
              background: `linear-gradient(45deg, ${theme.palette.primary.main}, ${theme.palette.secondary.main})`,
              WebkitBackgroundClip: "text",
              WebkitTextFillColor: "transparent",
              backgroundClip: "text",
            }}
          >
            Get In Touch
          </Typography>
        </Box>

        {/* Main Container */}
        <Paper
          elevation={0}
          sx={{
            border: `2px solid ${theme.palette.primary.main}40`,
            borderRadius: "24px",
            overflow: "hidden",
            background: `linear-gradient(135deg, ${theme.palette.background.paper}30, ${theme.palette.background.lightBlue}80)`,
            backdropFilter: "blur(10px)",
          }}
        >
          <Box sx={{ p: { xs: 3, md: 6 } }}>
            <Stack spacing={4}>
              {/* Contact Info Cards */}
              <Box>
                <Typography
                  variant="h5"
                  sx={{
                    color: theme.palette.primary.light,
                    mb: 3,
                    display: "flex",
                    alignItems: "center",
                    gap: 1,
                  }}
                >
                  <EmailIcon /> Contact Information
                </Typography>
                <Stack spacing={2}>{contactItems}</Stack>
              </Box>

              {/* Social Links */}
              <Box>
                <Typography
                  variant="h5"
                  sx={{
                    color: theme.palette.primary.light,
                    mb: 3,
                    display: "flex",
                    alignItems: "center",
                    gap: 1,
                  }}
                >
                  <TelegramIcon /> Connect With Me
                </Typography>
                <Stack
                  direction="row"
                  justifyContent="center"
                  sx={{ flexWrap: "wrap", gap: "16px", rowGap: "16px" }}
                >
                  {socialItems}
                </Stack>
              </Box>

              {/* Stats/Info Card */}
              <Paper
                sx={{
                  p: 3,
                  borderRadius: "16px",
                  background: `linear-gradient(135deg, ${theme.palette.primary.dark}20, ${theme.palette.secondary.dark}20)`,
                  border: `1px solid ${theme.palette.primary.light}20`,
                }}
              >
                <Stack spacing={1}>
                  <Typography
                    variant="h6"
                    sx={{ color: theme.palette.primary.light }}
                  >
                    Quick Response
                  </Typography>
                  <Typography
                    variant="body2"
                    sx={{ color: theme.palette.text.secondary }}
                  >
                    I typically respond within 24 hours. For urgent matters,
                    feel free to use Telegram.
                  </Typography>
                </Stack>
              </Paper>
            </Stack>
          </Box>
        </Paper>

        {/* Footer Note */}
        <Typography
          variant="body2"
          sx={{
            textAlign: "center",
            mt: 6,
            color: theme.palette.text.secondary,
            opacity: 0.8,
          }}
        >
          © {new Date().getFullYear()} Pouriya Sabouri, All rights served.
        </Typography>
      </Container>
    </Box>
  );
}
