import {
  Stack,
  Typography,
  useMediaQuery,
  useTheme,
  Box,
  IconButton,
} from "@mui/material";
import { ArrowRightAlt, Code } from "@mui/icons-material";
import { motion, useScroll, useTransform } from "framer-motion";
import { useRef } from "react";

export default function HeroContent() {
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down("lg"));
  const containerRef = useRef(null);
  const { scrollYProgress } = useScroll({
    target: containerRef,
    offset: ["start start", "end start"],
  });

  const y = useTransform(scrollYProgress, [0, 1], [0, 100]);
  const opacity = useTransform(scrollYProgress, [0, 0.5], [1, 0]);

  const content = {
    quote:
      "Programming for me is like solving a puzzle; each component is a piece, and the joy comes when they all work together!",
    introduction: {
      prefix: "I am",
      name: "Pouriya Sabouri",
      suffix:
        "I specialize in creating beautiful, performant, and accessible web experiences using modern technologies",
    },
    features: [
      "JavaScript (ES6+)",
      "React.js, Next.js",
      "Redux, Zustand",
      "Framer-Motion, GSAP",
      "Node.js",
      "Express.js",
    ],
  };

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.2,
        delayChildren: 0.3,
      },
    },
  };

  const itemVariants = {
    hidden: {
      opacity: 0,
      y: 30,
      filter: "blur(10px)",
    },
    visible: {
      opacity: 1,
      y: 0,
      filter: "blur(0px)",
      transition: {
        type: "spring",
        damping: 12,
        stiffness: 100,
      },
    },
  };

  const nameVariants = {
    initial: {
      scale: 1,
      textShadow: "0 0 0px rgba(0,0,0,0)",
    },
    animate: {
      scale: [1, 1.01, 1],
      textShadow: [
        "0 0 0px rgba(0,0,0,0)",
        "0 0 20px rgba(100, 100, 255, 0.3)",
        "0 0 0px rgba(0,0,0,0)",
      ],
      transition: {
        duration: 2,
        repeat: Infinity,
        ease: "easeInOut",
      },
    },
  };

  return (
    <Stack
      ref={containerRef}
      component={motion.div}
      style={{ y, opacity }}
      variants={containerVariants}
      initial="hidden"
      animate="visible"
      sx={{
        flex: 1,
        maxWidth: 650,
        alignItems: isMobile ? "center" : "flex-start",
        textAlign: isMobile ? "center" : "left",
        gap: 4,
        position: "relative",
      }}
    >
      {/* Animated background accent */}
      <motion.div
        initial={{ opacity: 0, scale: 0.8 }}
        animate={{
          opacity: 0.1,
          scale: 1,
          rotate: 360,
        }}
        transition={{
          duration: 20,
          repeat: Infinity,
          ease: "linear",
        }}
        style={{
          position: "absolute",
          top: -100,
          left: -100,
          width: 300,
          height: 300,
          background: `radial-gradient(circle, ${theme.palette.primary.main}30, transparent 70%)`,
          zIndex: -1,
        }}
      />

      <Typography
        component={motion.p}
        variants={itemVariants}
        variant="h6"
        fontStyle="italic"
        sx={{
          position: "relative",
          "&::before": {
            content: '""',
            position: "absolute",
            left: -20,
            top: 0,
            bottom: 0,
            width: 4,
            background: `linear-gradient(to bottom, transparent, ${theme.palette.primary.main}, transparent)`,
            borderRadius: 2,
          },
        }}
      >
        {content.quote}
      </Typography>

      <Stack spacing={2} component={motion.div} variants={containerVariants}>
        <Typography
          component={motion.p}
          variants={itemVariants}
          color="text.secondary"
          sx={{ letterSpacing: 1 }}
        >
          {content.introduction.prefix}
        </Typography>

        <Typography
          component={motion.h2}
          variants={nameVariants}
          initial="initial"
          animate="animate"
          variant="h3"
          sx={{
            fontWeight: 900,
            background: `linear-gradient(135deg, 
              ${theme.palette.primary.main}, 
              ${theme.palette.secondary.light}, 
              #ff6b6b, 
              ${theme.palette.primary.main})`,
            backgroundClip: "text",
            WebkitTextFillColor: "transparent",
            backgroundSize: "300% 300%",
            position: "relative",
            display: "inline-block",
          }}
        >
          {content.introduction.name}
        </Typography>

        <Typography
          component={motion.p}
          variants={itemVariants}
          sx={{
            fontSize: "1.1rem",
            lineHeight: 1.6,
          }}
        >
          {content.introduction.suffix}
        </Typography>
      </Stack>

      {/* Skills */}
      <Stack
        direction="row"
        flexWrap="wrap"
        gap={1}
        component={motion.div}
        variants={containerVariants}
      >
        {content.features.map((item, index) => (
          <Box
            key={item}
            component={motion.div}
            variants={itemVariants}
            whileHover={{
              scale: 1.05,
              y: -3,
              boxShadow: `0 10px 20px ${theme.palette.primary.main}30`,
              transition: { type: "spring", stiffness: 400 },
            }}
            whileTap={{ scale: 0.95 }}
            sx={{
              px: 2,
              py: 0.8,
              borderRadius: 20,
              fontSize: "0.85rem",
              border: `1px solid ${theme.palette.primary.main}40`,
              background: `linear-gradient(145deg, 
                ${theme.palette.background.paper}80, 
                ${theme.palette.background.default}80)`,
              backdropFilter: "blur(10px)",
              cursor: "pointer",
              position: "relative",
              overflow: "hidden",
              "&::before": {
                content: '""',
                position: "absolute",
                top: 0,
                left: "-100%",
                width: "100%",
                height: "100%",
                background: `linear-gradient(90deg, transparent, ${theme.palette.primary.main}20, transparent)`,
                transition: "left 0.5s",
              },
              "&:hover::before": {
                left: "100%",
              },
            }}
          >
            {item}
          </Box>
        ))}
      </Stack>

      {/*  code Button */}
      <IconButton
        component={motion.button}
        variants={itemVariants}
        whileHover={{
          scale: 1.1,
          rotate: 90,
          boxShadow: `0 0 30px ${theme.palette.primary.main}40`,
        }}
        whileTap={{ scale: 0.9 }}
        sx={{
          mt: 2,
          width: 56,
          height: 56,
          background: `linear-gradient(135deg, 
            ${theme.palette.primary.main}20, 
            ${theme.palette.secondary.main}20)`,
          backdropFilter: "blur(10px)",
          border: `1px solid ${theme.palette.primary.main}30`,
        }}
      >
        <motion.div
          animate={{ rotate: 360 }}
          transition={{
            duration: 10,
            repeat: Infinity,
            ease: "linear",
          }}
        >
          <Code sx={{ fontSize: 28 }} />
        </motion.div>
      </IconButton>
    </Stack>
  );
}
