import { Box, Stack, Typography, useMediaQuery, useTheme } from "@mui/material";

export default function HeroPicture({ mousePosition }) {
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down("md"));

  return (
    <Box
      sx={{
        position: "relative",
        zIndex: 2,
        perspective: "1000px",
        transformStyle: "preserve-3d",
      }}
    >
      {/* Glow effect behind image */}
      <Box
        sx={{
          position: "absolute",
          width: "110%",
          height: "110%",
          top: "-5%",
          left: "-5%",
          background: `radial-gradient(circle, ${theme.palette.primary.main}30 0%, transparent 70%)`,
          filter: "blur(20px)",
          borderRadius: "20px",
          opacity: 0.5,
        }}
      />

      {/* Main Image Container */}
      <Box
        sx={{
          width: { xs: "280px", md: "350px", lg: "500px" },
          height: { xs: "370px", md: "467px", lg: "633px" },
          borderRadius: "20px",
          overflow: "hidden",
          position: "relative",
          transform: `
              rotateY(${mousePosition.x}deg)
              rotateX(${-mousePosition.y}deg)
              translateZ(50px)
            `,
          transition: "all 0.1s ease-out",
          boxShadow: `
              0 20px 40px ${theme.palette.common.black}50,
              inset 0 0 60px ${theme.palette.primary.dark}30
            `,
          border: `2px solid ${theme.palette.primary.main}30`,
        }}
      >
        <img
          src="/media/pouriya-sabouri.png"
          alt="پوریا صبوری"
          style={{
            width: "100%",
            height: "100%",
            // objectFit: "cover",
            filter: "drop-shadow(0 10px 30px rgba(0,0,0,0.5))",
          }}
        />

        {/* Floating Elements */}
        <Box
          sx={{
            position: "absolute",
            top: "10%",
            right: "-20px",
            width: "60px",
            height: "60px",
            borderRadius: "50%",
            background: `linear-gradient(45deg, ${theme.palette.primary.main}, ${theme.palette.secondary.light})`,
            animation: "floatElement 3s ease-in-out infinite",
            display: { xs: "none", md: "block" },
            "@keyframes floatElement": {
              "0%, 100%": { transform: "translateY(0)" },
              "50%": { transform: "translateY(-20px)" },
            },
          }}
        />

        <Box
          sx={{
            position: "absolute",
            bottom: "15%",
            left: "-15px",
            width: "40px",
            height: "40px",
            borderRadius: "12px",
            backgroundColor: theme.palette.success.main,
            opacity: 0.8,
            animation: "floatElement 2.5s ease-in-out infinite 0.5s",
            display: { xs: "none", md: "block" },
            transform: "rotate(45deg)",
          }}
        />
      </Box>

      {/* Decorative Border */}
      <Box
        sx={{
          position: "absolute",
          top: "10px",
          left: "10px",
          right: "10px",
          bottom: "10px",
          border: `1px solid ${theme.palette.primary.main}20`,
          borderRadius: "16px",
          pointerEvents: "none",
        }}
      />
    </Box>
  );
}
