import React, { useState } from "react";
import {
  Box,
  Typography,
  Card,
  CardContent,
  Chip,
  IconButton,
  Stack,
} from "@mui/material";
import { motion } from "framer-motion";
import GitHubIcon from "@mui/icons-material/GitHub";
import LaunchIcon from "@mui/icons-material/Launch";
const ProjectCard = ({ project }) => {
  const [isHovered, setIsHovered] = useState(false);

  return (
    <motion.div
      transition={{ type: "spring", stiffness: 300 }}
      onHoverStart={() => setIsHovered(true)}
      onHoverEnd={() => setIsHovered(false)}
    >
      <Card
        sx={{
          height: "100%",
          background: `
            linear-gradient(135deg, 
              rgba(255, 255, 255, 0.08) 0%,
              rgba(255, 255, 255, 0.03) 100%
            )
          `,
          backdropFilter: "blur(20px)",
          border: "1px solid rgba(255, 255, 255, 0.1)",
          borderRadius: 3,
          overflow: "hidden",
          position: "relative",
          
        }}
      >
        {/* Project Image/Placeholder */}
        <Box
          sx={{
            height: "200px",
            position: "relative",
            overflow: "hidden",
            background: `linear-gradient(45deg, ${project.color}20, ${project.color}10)`,
          }}
        >
          <motion.div
            animate={isHovered ? { scale: 1.1 } : { scale: 1 }}
            transition={{ duration: 0.5 }}
          >
            <Box
              sx={{
                width: "100%",
                height: "100%",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                background: `radial-gradient(circle at center, ${project.color}30, transparent 70%)`,
              }}
            >
              <project.icon
                sx={{
                  fontSize: 80,
                  color: project.color,
                  opacity: 0.8,
                }}
              />
            </Box>
          </motion.div>
        </Box>

        <CardContent sx={{ p: 3 }}>
          <Stack spacing={2}>
            <Box>
              <Typography variant="h6" fontWeight={700} gutterBottom>
                {project.title}
              </Typography>
              <Typography variant="body2" color="text.secondary" sx={{ height:"50px" }}>
                {project.description}
              </Typography>
            </Box>

            {/* Tech Stack */}
            <Box>
              <Typography variant="caption" color="text.secondary" gutterBottom>
                Tech Stack
              </Typography>
              <Stack direction="row" spacing={1} flexWrap="wrap" useFlexGap>
                {project.tech.map((tech, idx) => (
                  <Chip
                    key={idx}
                    label={tech}
                    size="small"
                    sx={{
                      backgroundColor: `${project.color}20`,
                      color: project.color,
                      border: `1px solid ${project.color}40`,
                      fontSize: "0.7rem",
                    }}
                  />
                ))}
              </Stack>
            </Box>

            {/* Stats */}
            <Stack
              direction="row"
              justifyContent="end"
              alignItems="center"
              sx={{  }}
            >
              {/* Action Buttons */}
              <Stack direction="row" spacing={1}>
                <IconButton
                  size="small"
                  href={project.links.github}
                  target="_blank"
                  sx={{
                    backgroundColor: "rgba(255, 255, 255, 0.05)",
                    "&:hover": { backgroundColor: "rgba(255, 255, 255, 0.1)" },
                  }}
                >
                  <GitHubIcon fontSize="small" />
                </IconButton>
                <IconButton
                  size="small"
                  href={project.links.demo}
                  target="_blank"
                  sx={{
                    backgroundColor: "rgba(255, 255, 255, 0.05)",
                    "&:hover": { backgroundColor: "rgba(255, 255, 255, 0.1)" },
                  }}
                >
                  <LaunchIcon fontSize="small" />
                </IconButton>
              </Stack>
            </Stack>
          </Stack>
        </CardContent>

        {/* Hover Glow Effect */}
        <Box
          sx={{
            position: "absolute",
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            background: `radial-gradient(circle at 50% 0%, ${project.color}15, transparent 70%)`,
            opacity: isHovered ? 1 : 0,
            transition: "opacity 0.3s ease",
            pointerEvents: "none",
          }}
        />
      </Card>
    </motion.div>
  );
};
export default ProjectCard;
