import { Box, Chip, Grid, Stack, Typography, useTheme } from "@mui/material";
import { motion } from "framer-motion";

const cardVariants = {
  hidden: { opacity: 0, y: 30, scale: 0.9 },
  visible: {
    opacity: 1,
    y: 0,
    scale: 1,
    transition: { type: "spring", stiffness: 100, damping: 12 },
  },
  hover: {
    y: -2,
    scale: 1.02,
    transition: { type: "spring", stiffness: 400, damping: 15 },
  },
};

const iconVariants = {
  hidden: { rotate: -90, scale: 0 },
  visible: {
    rotate: 0,
    scale: 1,
    transition: { type: "spring", stiffness: 200, damping: 15 },
  },
  hover: { rotate: [0, 10, -10, 0], transition: { duration: 0.5 } },
};

const chipVariants = {
  hidden: { opacity: 0, scale: 0.8 },
  visible: (i) => ({
    opacity: 1,
    scale: 1,
    transition: { delay: i * 0.05 + 0.3, type: "spring", stiffness: 150 },
  }),
  hover: { scale: 1.02, y: -2, transition: { duration: 0.2 } },
};
export default function SkillsCard({ skill }) {
  const theme = useTheme();

  return (
    <Grid size={{ xs: 12, md: 6, xl: 4 }} sx={{ p: 1 }}>
      <motion.div
        variants={cardVariants}
        initial="hidden"
        whileInView="visible"
        whileHover="hover"
        viewport={{ once: true, amount: 0.3 }}
        style={{ width: "100%", height: "100%" }}
      >
        <Box
          sx={{
            backgroundColor: theme.palette.background.paper,
            borderRadius: 2,
            p: 3,
            border: `1px solid ${theme.palette.divider}`,
            height: "100%",
          }}
        >
          {/* Header */}
          <Stack direction="row" spacing={2} alignItems="center" mb={2}>
            <motion.div variants={iconVariants} whileHover="hover">
              <Box
                sx={{
                  width: 56,
                  height: 56,
                  borderRadius: 1.5,
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  backgroundColor: `${skill.color}15`,
                  color: skill.color,
                }}
              >
                {skill.icon}
              </Box>
            </motion.div>

            <Box>
              <Typography variant="h6" fontWeight={600}>
                {skill.title}
              </Typography>
              <Typography variant="body2" color="text.secondary">
                {skill.level}% proficiency
              </Typography>
            </Box>
          </Stack>

          {/* Chips */}
          <Box sx={{ display: "flex", flexWrap: "wrap", gap: 1, mb: 2.5 }}>
            {skill.items.map((item, i) => (
              <motion.div
                key={i}
                custom={i}
                variants={chipVariants}
                initial="hidden"
                whileInView="visible"
                whileHover="hover"
                viewport={{ once: true }}
              >
                <Chip
                  label={item}
                  size="small"
                  sx={{
                    backgroundColor: `${item?.color}10`,
                    color: item?.color,
                    border: `1px solid ${item?.color}30`,
                    fontWeight: 500,
                    fontSize: "0.8rem",
                    height: 28,
                  }}
                />
              </motion.div>
            ))}
          </Box>

          {/* Progress */}
          <Box
            sx={{
              height: 6,
              borderRadius: 3,
              backgroundColor: `${skill.color}15`,
              overflow: "hidden",
            }}
          >
            <Box
              sx={{
                height: "100%",
                width: `${skill.level}%`,
                backgroundColor: skill.color,
              }}
            />
          </Box>
        </Box>
      </motion.div>
    </Grid>
  );
}
