import React from "react";
import { liveProjectsData } from "../../../Data/liveProjects";
import { useParams, Link } from "react-router-dom";
import { trainProjectsData } from "../../../Data/trainProjects";
import { ArrowBack } from "@mui/icons-material";
import {
  alpha,
  Box,
  Button,
  Container,
  Fade,
  Stack,
  Typography,
  useTheme,
  Divider,
  Paper,
  IconButton,
} from "@mui/material";
import {
  GitHub,
  OpenInNew,
  CheckCircleOutline,
  EventAvailable,
  Person,
  Group,
  Build,
  Update,
} from "@mui/icons-material";
import { motion } from "framer-motion";
import SeoHelmet from "../../../Components/SeoHelmet";

export default function ProjectDetail() {
  const theme = useTheme();
  const { code } = useParams();

  const project = code?.startsWith("train")
    ? trainProjectsData?.find((pr) => pr?._id == code)
    : liveProjectsData?.find((pr) => pr?._id == code);

  if (!project) {
    return (
      <Box
        sx={{
          minHeight: "100vh",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
        }}
      >
        <Typography variant="h4" color="error">
          Project not found
        </Typography>
      </Box>
    );
  }

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.1,
        delayChildren: 0.2,
      },
    },
  };

  const itemVariants = {
    hidden: {
      opacity: 0,
      y: 30,
      filter: "blur(10px)",
    },
    visible: {
      opacity: 1,
      y: 0,
      filter: "blur(0px)",
      transition: {
        type: "spring",
        damping: 12,
        stiffness: 100,
      },
    },
  };

  const glowAnimation = {
    animate: {
      boxShadow: [
        `0 0 0px ${alpha(project.color, 0)}`,
        `0 0 20px ${alpha(project.color, 0.5)}`,
        `0 0 0px ${alpha(project.color, 0)}`,
      ],
      transition: {
        duration: 2,
        repeat: Infinity,
        repeatDelay: 1,
      },
    },
  };

  const featureItems = project?.keyFeatures?.map((feature, i) => (
    <motion.div
      key={i}
      variants={itemVariants}
      custom={i}
      initial="hidden"
      animate="visible"
    >
      <Stack direction="row" alignItems="center" gap={1.5}>
        <motion.div
          animate={{
            scale: [1, 1.2, 1],
          }}
          transition={{
            duration: 2,
            repeat: Infinity,
            delay: i * 0.2,
          }}
        >
          <CheckCircleOutline
            sx={{
              fontSize: "1.2rem",
              color: project.color,
            }}
          />
        </motion.div>
        <Typography
          variant="body1"
          sx={{
            color: theme.palette.text.secondary,
            lineHeight: 1.6,
          }}
        >
          {feature}
        </Typography>
      </Stack>
    </motion.div>
  ));

  const toolItems = project?.tools?.map((item, index) => (
    <Box
      key={item}
      component={motion.div}
      variants={itemVariants}
      whileHover={{
        scale: 1.05,
        y: -3,
        boxShadow: `0 10px 20px ${project.color}`,
        transition: { type: "spring", stiffness: 400 },
      }}
      whileTap={{ scale: 0.95 }}
      sx={{
        px: 2,
        py: 0.8,
        borderRadius: 20,
        fontSize: "0.85rem",
        border: `1px solid ${project.color}`,
        background: `linear-gradient(145deg, 
                ${theme.palette.background.paper}80, 
                ${theme.palette.background.default}80)`,
        backdropFilter: "blur(10px)",
        cursor: "pointer",
        position: "relative",
        overflow: "hidden",
        "&::before": {
          content: '""',
          position: "absolute",
          top: 0,
          left: "-100%",
          width: "100%",
          height: "100%",
          background: `linear-gradient(90deg, transparent, ${project.color}, transparent)`,
          transition: "left 0.5s",
        },
        "&:hover::before": {
          left: "100%",
        },
      }}
    >
      {item}
    </Box>
  ));

  const imgItems = project.images && project.images.length > 0 && (
    <Fade in timeout={1000}>
      <Stack
        direction={{ xs: "column", md: "row" }}
        sx={{
          py: "4rem",
          gap: "2rem",
          justifyContent: "center",
          alignItems: "center",
        }}
      >
        {project.images.map((img, idx) => (
          <motion.div
            key={idx}
            initial={{ opacity: 0, y: 50 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6, delay: idx * 0.15 }}
            style={{
              width: "100%",
              position: "relative",
            }}
          >
            <Box
              sx={{
                position: "relative",
                width: "100%",
                height: {
                  xs: "250px",
                  sm: "350px",
                  md: "400px",
                  lg: "450px",
                },
                borderRadius: "20px",
                overflow: "hidden",
                cursor: "pointer",
                transition: "all 0.4s cubic-bezier(0.2, 0.9, 0.4, 1.1)",
                "&:hover": {
                  transform: "translateY(-8px)",
                  "& .image-overlay": {
                    opacity: 1,
                  },
                  "& .image-caption": {
                    transform: "translateY(0)",
                    opacity: 1,
                  },
                },
              }}
            >
              {/* Image */}
              <motion.img
                whileHover={{ scale: 1.05 }}
                transition={{ duration: 0.5 }}
                style={{
                  width: "100%",
                  height: "100%",
                  objectFit: "cover",
                }}
                src={img}
                alt={`${project.title} screenshot ${idx + 1}`}
              />

              {/* Gradient Overlay on Hover */}
              <Box
                className="image-overlay"
                sx={{
                  position: "absolute",
                  top: 0,
                  left: 0,
                  right: 0,
                  bottom: 0,
                  background: `linear-gradient(to top, ${alpha(project.color, 0.3)}, transparent)`,
                  opacity: 0,
                  transition: "opacity 0.4s ease",
                }}
              />

              {/* Caption that slides up on hover */}
              <Box
                className="image-caption"
                sx={{
                  position: "absolute",
                  bottom: 0,
                  left: 0,
                  right: 0,
                  p: 2,
                  background: `linear-gradient(to top, ${alpha(theme.palette.background.default, 0.9)}, transparent)`,
                  transform: "translateY(100%)",
                  opacity: 0,
                  transition: "all 0.3s ease",
                }}
              >
                <Typography
                  variant="caption"
                  sx={{
                    color: "white",
                    fontWeight: 500,
                    display: "block",
                    textAlign: "center",
                  }}
                >
                  {`${project.title} - Screenshot ${idx + 1}`}
                </Typography>
              </Box>

              {/* Subtle shine effect on corner */}
              <Box
                sx={{
                  position: "absolute",
                  top: 0,
                  left: 0,
                  width: "100px",
                  height: "100px",
                  background: `linear-gradient(135deg, ${alpha(project.color, 0.2)} 0%, transparent 100%)`,
                  pointerEvents: "none",
                }}
              />
            </Box>
          </motion.div>
        ))}
      </Stack>
    </Fade>
  );

  // تبدیل نقش به فارسی
  const getRoleLabel = (role) => {
    switch (role) {
      case "frontend":
        return "Frontend Developer";
      case "backend":
        return "Backend Developer";
      case "fullstack":
        return "Fullstack Developer";
      default:
        return role;
    }
  };

  // تبدیل نوع مشارکت به فارسی
  const getContributionLabel = (type) => {
    switch (type) {
      case "full":
        return "Full Development (0 to 100)";
      case "update":
        return "Project Update & Maintenance";
      default:
        return type;
    }
  };

  // تبدیل نوع همکاری به فارسی
  const getCollaborationLabel = (type) => {
    switch (type) {
      case "alone":
        return "Solo Project";
      case "withTeam":
        return "Team Collaboration";
      default:
        return type;
    }
  };

  return (
    <>
      <SeoHelmet
        title={`${project.title} | پروژه پوریا صبوری`}
        description={`${project.description.substring(0, 150)}... | توسعه با ${project.tools?.slice(0, 3).join(", ")} | زمان تحویل: ${project.doneTime}`}
        keywords={`${project.title}, پروژه فرانت اند, react project, ${project.tools?.join(", ")}`}
        ogTitle={project.title}
        ogDescription={project.description.substring(0, 120)}
        ogImage={project.images?.[0] || "/og-image.jpg"}
        ogType="article"
      />
      <Box
        sx={{
          minHeight: "100svh",
          background: `radial-gradient(circle at 20% 30%, ${alpha(project.color, 0.02)} 0%, transparent 70%)`,
          overflow: "hidden",
        }}
      >
        <Container maxWidth="xxl" sx={{ py: { xs: "4rem", md: "5rem" } }}>
          <Stack spacing={5}>
            {/* Title and Buttons */}
            <motion.div
              initial={{ x: -50, opacity: 0 }}
              animate={{ x: 0, opacity: 1 }}
              transition={{ duration: 0.6, type: "spring" }}
            >
              <Stack
                direction={{ xs: "column", lg: "row" }}
                sx={{
                  justifyContent: "space-between",
                  alignItems: { xs: "flex-start", lg: "center" },
                  gap: { xs: 2, lg: 0 },
                }}
              >
                <Box>
                  <Typography
                    component="h1"
                    sx={{
                      fontSize: {
                        xs: "2rem",
                        sm: "2.5rem",
                        md: "3rem",
                      },
                      fontWeight: 800,
                      background: `linear-gradient(135deg, ${project.color}, ${theme.palette.secondary.main})`,
                      backgroundClip: "text",
                      WebkitBackgroundClip: "text",
                      color: "transparent",
                      lineHeight: 1.2,
                      letterSpacing: "-0.02em",
                      mt:{xs:"2rem" , md:"0"}
                    }}
                  >
                    {project.title}
                  </Typography>

                  <motion.div
                    initial={{ width: 0 }}
                    animate={{ width: "60px" }}
                    transition={{ delay: 0.3, duration: 0.6 }}
                  >
                    <Box
                      sx={{
                        height: "3px",
                        background: `linear-gradient(90deg, ${project.color}, transparent)`,
                        mt: 1,
                        borderRadius: "2px",
                      }}
                    />
                  </motion.div>
                </Box>

                <Stack direction="row" gap={1.5}>
                  <motion.div
                    whileHover={{ scale: 1.02 }}
                    whileTap={{ scale: 0.98 }}
                  >
                    <Button
                      variant="contained"
                      href={project.liveUrl}
                      target="_blank"
                      startIcon={<OpenInNew sx={{ fontSize: "1rem" }} />}
                      sx={{
                        height: "40px",
                        px: 3,
                        background: project.color,
                        borderRadius: "10px",
                        fontWeight: 600,
                        textTransform: "none",
                        fontSize: "0.85rem",
                        "&:hover": {
                          background: alpha(project.color, 0.85),
                        },
                      }}
                    >
                      Live Demo
                    </Button>
                  </motion.div>

                  {project.githubUrl && (
                    <motion.div
                      whileHover={{ scale: 1.02 }}
                      whileTap={{ scale: 0.98 }}
                    >
                      <Button
                        variant="outlined"
                        href={project.githubUrl}
                        target="_blank"
                        startIcon={<GitHub sx={{ fontSize: "1rem" }} />}
                        sx={{
                          height: "40px",
                          px: 3,
                          borderColor: alpha(project.color, 0.3),
                          color: project.color,
                          borderRadius: "10px",
                          fontWeight: 600,
                          textTransform: "none",
                          fontSize: "0.85rem",
                          "&:hover": {
                            borderColor: project.color,
                            background: alpha(project.color, 0.05),
                          },
                        }}
                      >
                        Code
                      </Button>
                    </motion.div>
                  )}
                </Stack>
              </Stack>
            </motion.div>

            {/* Description */}
            <motion.div
              variants={itemVariants}
              initial="hidden"
              animate="visible"
            >
              <Paper
                elevation={0}
                sx={{
                  p: { xs: 3, md: 4 },
                  background: alpha(theme.palette.background.paper, 0.3),
                  backdropFilter: "blur(8px)",
                  borderRadius: "20px",
                  border: `1px solid ${alpha(project.color, 0.08)}`,
                }}
              >
                <Typography
                  variant="body1"
                  sx={{
                    color: theme.palette.text.primary,
                    lineHeight: 1.7,
                    fontSize: "0.95rem",
                  }}
                >
                  {project.longDesc || project.description}
                </Typography>
              </Paper>
            </motion.div>
            {/* Project Info Cards - My Role, Team, Contribution */}
            <motion.div
              variants={containerVariants}
              initial="hidden"
              animate="visible"
            >
              <Stack
                direction={{ xs: "column", sm: "row" }}
                spacing={2}
                sx={{
                  justifyContent: "center",
                  my: 2,
                }}
              >
                {/* My Role Card */}
                <Box
                  sx={{
                    flex: 1,
                    minWidth: { xs: "100%", sm: "150px" },
                  }}
                >
                  <motion.div
                    variants={itemVariants}
                    whileHover={{
                      y: -5,
                      transition: { type: "spring", stiffness: 300 },
                    }}
                  >
                    <Box
                      sx={{
                        p: 2,
                        borderRadius: "16px",
                        background: alpha(theme.palette.background.paper, 0.4),
                        backdropFilter: "blur(8px)",
                        textAlign: "center",
                        border: `1px solid ${alpha(project.color, 0.1)}`,
                        transition: "all 0.3s ease",
                        cursor: "pointer",
                        "&:hover": {
                          borderColor: alpha(project.color, 0.4),
                          background: alpha(
                            theme.palette.background.paper,
                            0.6,
                          ),
                          boxShadow: `0 8px 20px ${alpha(project.color, 0.15)}`,
                        },
                      }}
                    >
                      <motion.div
                        animate={{
                          scale: [1, 1.1, 1],
                        }}
                        transition={{
                          duration: 2,
                          repeat: Infinity,
                          repeatDelay: 3,
                        }}
                      >
                        <Person
                          sx={{
                            color: project.color,
                            mb: 1,
                            fontSize: "1.8rem",
                          }}
                        />
                      </motion.div>
                      <Typography
                        variant="h6"
                        fontWeight="700"
                        sx={{ fontSize: "1rem", mb: 0.5 }}
                      >
                        {getRoleLabel(project.myRole)}
                      </Typography>
                      <Typography variant="caption" color="text.secondary">
                        My Role
                      </Typography>
                    </Box>
                  </motion.div>
                </Box>

                {/* Team Size Card */}
                <Box
                  sx={{
                    flex: 1,
                    minWidth: { xs: "100%", sm: "150px" },
                  }}
                >
                  <motion.div
                    variants={itemVariants}
                    whileHover={{
                      y: -5,
                      transition: { type: "spring", stiffness: 300 },
                    }}
                  >
                    <Box
                      sx={{
                        p: 2,
                        borderRadius: "16px",
                        background: alpha(theme.palette.background.paper, 0.4),
                        backdropFilter: "blur(8px)",
                        textAlign: "center",
                        border: `1px solid ${alpha(project.color, 0.1)}`,
                        transition: "all 0.3s ease",
                        cursor: "pointer",
                        "&:hover": {
                          borderColor: alpha(project.color, 0.4),
                          background: alpha(
                            theme.palette.background.paper,
                            0.6,
                          ),
                          boxShadow: `0 8px 20px ${alpha(project.color, 0.15)}`,
                        },
                      }}
                    >
                      <motion.div
                        animate={{
                          rotate: [0, 5, -5, 0],
                        }}
                        transition={{
                          duration: 3,
                          repeat: Infinity,
                          repeatDelay: 2,
                        }}
                      >
                        {project.collaborationType === "alone" ? (
                          <Person
                            sx={{
                              color: project.color,
                              mb: 1,
                              fontSize: "1.8rem",
                            }}
                          />
                        ) : (
                          <Group
                            sx={{
                              color: project.color,
                              mb: 1,
                              fontSize: "1.8rem",
                            }}
                          />
                        )}
                      </motion.div>
                      <Typography
                        variant="h6"
                        fontWeight="700"
                        sx={{ fontSize: "1rem", mb: 0.5 }}
                      >
                        {project.teamSize === 1
                          ? "Just Me"
                          : `${project.teamSize} Members`}
                      </Typography>
                      <Typography variant="caption" color="text.secondary">
                        {getCollaborationLabel(project.collaborationType)}
                      </Typography>
                    </Box>
                  </motion.div>
                </Box>

                {/* Contribution Type Card */}
                <Box
                  sx={{
                    flex: 1,
                    minWidth: { xs: "100%", sm: "150px" },
                  }}
                >
                  <motion.div
                    variants={itemVariants}
                    whileHover={{
                      y: -5,
                      transition: { type: "spring", stiffness: 300 },
                    }}
                  >
                    <Box
                      sx={{
                        p: 2,
                        borderRadius: "16px",
                        background: alpha(theme.palette.background.paper, 0.4),
                        backdropFilter: "blur(8px)",
                        textAlign: "center",
                        border: `1px solid ${alpha(project.color, 0.1)}`,
                        transition: "all 0.3s ease",
                        cursor: "pointer",
                        "&:hover": {
                          borderColor: alpha(project.color, 0.4),
                          background: alpha(
                            theme.palette.background.paper,
                            0.6,
                          ),
                          boxShadow: `0 8px 20px ${alpha(project.color, 0.15)}`,
                        },
                      }}
                    >
                      <motion.div
                        animate={{
                          scale: [1, 1.15, 1],
                        }}
                        transition={{
                          duration: 2.5,
                          repeat: Infinity,
                          repeatDelay: 2.5,
                        }}
                      >
                        {project.contributionType === "full" ? (
                          <Build
                            sx={{
                              color: project.color,
                              mb: 1,
                              fontSize: "1.8rem",
                            }}
                          />
                        ) : (
                          <Update
                            sx={{
                              color: project.color,
                              mb: 1,
                              fontSize: "1.8rem",
                            }}
                          />
                        )}
                      </motion.div>
                      <Typography
                        variant="h6"
                        fontWeight="700"
                        sx={{ fontSize: "0.85rem", mb: 0.5 }}
                      >
                        {getContributionLabel(project.contributionType)}
                      </Typography>
                      <Typography variant="caption" color="text.secondary">
                        Contribution
                      </Typography>
                    </Box>
                  </motion.div>
                </Box>
              </Stack>
            </motion.div>

            {/* Delivery Time */}
            <motion.div
              variants={itemVariants}
              initial="hidden"
              animate="visible"
              style={{ display: "flex", justifyContent: "center" }}
            >
              <Box
                sx={{
                  display: "inline-flex",
                  alignItems: "center",
                  gap: 2,
                  px: 3,
                  py: 1.5,
                  borderRadius: "50px",
                  background: alpha(theme.palette.background.paper, 0.3),
                  backdropFilter: "blur(8px)",
                  border: `1px solid ${alpha(theme.palette.secondary.main, 0.15)}`,
                }}
              >
                <Box
                  sx={{
                    display: "flex",
                    alignItems: "center",
                    gap: 1,
                  }}
                >
                  <EventAvailable
                    sx={{
                      fontSize: "1.1rem",
                      color: theme.palette.secondary.main,
                    }}
                  />
                  <Typography
                    variant="caption"
                    sx={{
                      color: theme.palette.text.secondary,
                      fontWeight: 500,
                      letterSpacing: "0.5px",
                    }}
                  >
                    Completed in
                  </Typography>
                </Box>

                <Box
                  sx={{
                    width: "1px",
                    height: "20px",
                    background: alpha(theme.palette.secondary.main, 0.3),
                  }}
                />

                <Typography
                  sx={{
                    fontSize: "1rem",
                    fontWeight: 600,
                    color: theme.palette.secondary.main,
                  }}
                >
                  {project.doneTime}
                </Typography>
              </Box>
            </motion.div>

            {/* Key Features Section */}
            <motion.div
              variants={containerVariants}
              initial="hidden"
              animate="visible"
            >
              <Stack spacing={2}>
                <Typography
                  variant="h6"
                  sx={{
                    color: project.color,
                    fontWeight: 600,
                    letterSpacing: "-0.3px",
                  }}
                >
                  Key Features
                </Typography>
                <Stack spacing={1.5}>{featureItems}</Stack>
              </Stack>
            </motion.div>

            {/* Tools & Technologies */}
            <motion.div
              variants={containerVariants}
              initial="hidden"
              animate="visible"
            >
              <Stack spacing={2}>
                <Typography
                  variant="h6"
                  sx={{
                    color: theme.palette.secondary.main,
                    fontWeight: 600,
                    letterSpacing: "-0.3px",
                  }}
                >
                  Tech Stack
                </Typography>
                <Stack
                  direction="row"
                  sx={{
                    flexWrap: "wrap",
                    gap: "10px",
                  }}
                >
                  {toolItems}
                </Stack>
              </Stack>
            </motion.div>
          </Stack>

          {/* Images Gallery */}
          {imgItems}

          {/* Back to Top Button */}
          <motion.div
            initial={{ opacity: 0, scale: 0 }}
            animate={{ opacity: 1, scale: 1 }}
            transition={{ delay: 1 }}
            style={{
              position: "fixed",
              bottom: "2rem",
              right: "2rem",
              zIndex: 1000,
            }}
          >
            <motion.div
              whileHover={{ scale: 1.1 }}
              whileTap={{ scale: 0.9 }}
              animate={glowAnimation}
            >
              <Button
                variant="contained"
                onClick={() => window.scrollTo({ top: 0, behavior: "smooth" })}
                sx={{
                  minWidth: "40px",
                  width: "40px",
                  height: "40px",
                  borderRadius: "12px",
                  background: project.color,
                  fontSize: "1.2rem",
                  "&:hover": {
                    background: alpha(project.color, 0.85),
                  },
                }}
              >
                ↑
              </Button>
            </motion.div>
          </motion.div>
        </Container>
        <motion.div
          initial={{ x: -50, opacity: 0 }}
          animate={{ x: 0, opacity: 1 }}
          transition={{ duration: 0.5 }}
          style={{
            position: "absolute",
            top: "2rem",
            left: "2rem",
            zIndex: 100,
          }}
        >
          <motion.div
            whileHover={{ scale: 1.05, x: -3 }}
            whileTap={{ scale: 0.95 }}
          >
            <IconButton
              component={Link}
              to="/projects"
              sx={{
                width: "40px",
                height: "40px",
                borderRadius: "10px",
                background: alpha(theme.palette.background.paper, 0.6),
                backdropFilter: "blur(8px)",
                border: `1px solid ${alpha(project.color, 0.2)}`,
                color: project.color,
                "&:hover": {
                  background: alpha(project.color, 0.1),
                  borderColor: project.color,
                },
              }}
            >
              <ArrowBack sx={{ fontSize: "1.2rem" }} />
            </IconButton>
          </motion.div>
        </motion.div>
      </Box>
    </>
  );
}
