import React from "react";
import { Box, Typography, Paper } from "@mui/material";
import { motion } from "framer-motion";

const SoftSkillCard = ({ skill, level, color = "#6366f1" }) => {
  const progress = (level / 5) * 100;

  return (
    <motion.div
      whileHover={{ y: -4 }}
      transition={{ duration: 0.2 }}
      style={{ height: "100%" }}
    >
      <Paper
        elevation={0}
        sx={{
          p: 3,
          height: "100%",
          borderRadius: 2,
          border: "1px solid",
          borderColor: "divider",
          transition: "all 0.2s ease",
          "&:hover": {
            borderColor: `${color}40`,
            boxShadow: `0 4px 12px ${color}10`,
          },
        }}
      >
        <Typography
          variant="h6"
          sx={{
            fontWeight: 500,
            mb: 2.5,
            color: "text.primary",
          }}
        >
          {skill}
        </Typography>

        <Box sx={{ width: "100%" }}>
          <Box sx={{ display: "flex", justifyContent: "space-between", mb: 1 }}>
            <Typography variant="caption" sx={{ color: "text.secondary" }}>
              Level {level}/5
            </Typography>
            <Typography
              variant="caption"
              sx={{ color: `${color}`, fontWeight: 500 }}
            >
              {progress}%
            </Typography>
          </Box>

          <Box
            sx={{
              height: 3,
              borderRadius: 1.5,
              bgcolor: "action.selected",
              overflow: "hidden",
            }}
          >
            <motion.div
              initial={{ width: 0 }}
              animate={{ width: `${progress}%` }}
              transition={{ duration: 0.6, ease: "easeOut" }}
              style={{
                height: "100%",
                backgroundColor: color,
                borderRadius: 1.5,
              }}
            />
          </Box>
        </Box>
      </Paper>
    </motion.div>
  );
};

export default SoftSkillCard;