import {
  Stack,
  Typography,
  Box,
  Chip,
  useTheme,
  Container,
  Grid,
} from "@mui/material";
import {
  Code,
  Storage,
  Animation,
  Terminal,
  Palette,
  RocketLaunch,
} from "@mui/icons-material";
import { motion } from "framer-motion";
import SkillsCard from "./SkillsCard";

const containerVariants = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: { staggerChildren: 0.2, delayChildren: 0.3 },
  },
};

export default function SkillsSection() {
  const theme = useTheme();

  const skills = [
    {
      title: "Frontend Development",
      icon: <Code fontSize="large" />,
      color: theme.palette.primary.main,
      items: ["JavaScript (ES6+)", "React.js", "Next.js", "Formik & Yup"],
      level: 65,
    },
    {
      title: "State Management",
      icon: <Storage fontSize="large" />,
      color: theme.palette.secondary.main,
      items: ["Redux Toolkit", "Zustand", "Context API"],
      level: 50,
    },
    {
      title: "UI Animation",
      icon: <Animation fontSize="large" />,
      color: theme.palette.error.main,
      items: ["Framer Motion", "GSAP"],
      level: 50,
    },
    {
      title: "Backend & APIs",
      icon: <Terminal fontSize="large" />,
      color: theme.palette.success.main,
      items: ["Node.js", "Express.js"],
      level: 40,
    },
    {
      title: "UI Styling",
      icon: <Palette fontSize="large" />,
      color: theme.palette.info.main,
      items: ["Material UI", "Tailwind", "Bootstrap", "SASS"],
      level: 80,
    },
    {
      title: "Tools",
      icon: <RocketLaunch fontSize="large" />,
      color: theme.palette.warning.main,
      items: ["Git & GitHub"],
      level: 60,
    },
  ];

  return (
    <Box
    id="skills-section"
      sx={(theme) => ({
        py: { xs: 6, md: 10 },
        minHeight: "100vh",
        position: "relative",
        overflow: "hidden",

        background: `
          radial-gradient(circle at 20% 50%, ${theme.palette.primary.dark}20 0%, transparent 40%),
          radial-gradient(circle at 80% 20%, ${theme.palette.secondary.dark}15 0%, transparent 40%),
          linear-gradient(135deg, ${theme.palette.background.default} 0%, ${theme.palette.background.lightBlue} 100%)
        `,
      })}
    >

      <Container maxWidth="xl" sx={{ zIndex:"1000" }}>
        {/* Header */}
        <Box textAlign="center" mb={{ xs: 6, md: 8 }}>
          <Typography
            variant="h2"
            fontWeight={700}
            mb={2}
            sx={{
              background: `linear-gradient(90deg, ${theme.palette.info.main} 40%, ${theme.palette.secondary.main})`,
              WebkitBackgroundClip: "text",
              WebkitTextFillColor: "transparent",
            }}
          >
           Tech Skills 
          </Typography>
          <Typography
            variant="h6"
            color="text.secondary"
            maxWidth={600}
            mx="auto"
          >
            Technologies and tools I use daily to build modern web applications
          </Typography>
        </Box>

        {/* Grid */}
        <motion.div
          variants={containerVariants}
          initial="hidden"
          whileInView="visible"
          viewport={{ once: true }}
        >
          <Grid container>
            {skills.map((skill) => (
              <SkillsCard key={skill.title} skill={skill} />
            ))}
          </Grid>
        </motion.div>
      </Container>
      {/* Particles Background */}
      <Box
        sx={{
          position: "absolute",
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          backgroundImage: `
          radial-gradient(circle at 1px 1px, ${theme.palette.primary.light}10 1px, transparent 0)
        `,
          backgroundSize: "50px 50px",
          opacity: 0.3,
          zIndex:"-10"
        }}
      />
    </Box>
  );
}
