import {
  Box,
  Container,
  Fade,
  Grid,
  IconButton,
  Stack,
  Tab,
  Tabs,
  Typography,
  useTheme,
} from "@mui/material";
import { AnimatePresence, motion } from "framer-motion";
import { useNavigate } from "react-router-dom";
import ProjectCard from "./ProjectsCard";
import { liveProjectsData } from "../../../Data/liveProjects";
import { Code, Group, Home, RemoveRedEye, Work } from "@mui/icons-material";
import { useState } from "react";
import { trainProjectsData } from "../../../Data/trainProjects";
import SeoHelmet from "../../../Components/SeoHelmet";

export default function Projects() {
  const theme = useTheme();
  const navigate = useNavigate();

  const [tabIndex, setTabIndex] = useState(0);
  const typoSx = {
    fontWeight: 900,
    background: `linear-gradient(135deg, 
              ${theme.palette.primary.main}, 
              ${theme.palette.secondary.light}, 
              #ff6b6b, 
              ${theme.palette.primary.main})`,
    backgroundClip: "text",
    WebkitTextFillColor: "transparent",
    backgroundSize: "300% 300%",
    position: "relative",
    display: "block",
    mb: "1rem",
  };
  const nameVariants = {
    initial: {
      scale: 1,
      textShadow: "0 0 0px rgba(0,0,0,0)",
    },
    animate: {
      scale: [1, 1.01, 1],
      textShadow: [
        "0 0 0px rgba(0,0,0,0)",
        "0 0 20px rgba(100, 100, 255, 0.3)",
        "0 0 0px rgba(0,0,0,0)",
      ],
      transition: {
        duration: 2,
        repeat: Infinity,
        ease: "easeInOut",
      },
    },
  };
  const LiveItems = liveProjectsData?.map((e, index) => {
    return (
      <Grid
        key={e?._id}
        sx={{ padding: "1rem", height: { xs: "200px", sm: "300px" } }}
        size={{ xs: 12, md: 6, xl: 4, exl: 3 }}
      >
        <ProjectCard e={e} />
      </Grid>
    );
  });
  const trainItems = trainProjectsData?.reverse()?.map((e, index) => {
    return (
      <Grid
        key={e?._id}
        sx={{ padding: "1rem", height: { xs: "200px", sm: "300px" } }}
        size={{ xs: 12, md: 6, xl: 4, exl: 3 }}
      >
        <ProjectCard e={e} />
      </Grid>
    );
  });
  return (
    <>
      <SeoHelmet
        title="نمونه کارها | پروژه‌های پوریا صبوری | Projects | pouriya sabouri portfolio"
        description="مجموعه پروژه‌های حرفه‌ای پوریا صبوری شامل پروژه‌های زنده و تمرینی با React، Next.js، و تکنولوژی‌های مدرن Frontend | پوریا صبوری - برنامه‌نویس فرانت‌اند"
        keywords="پروژه‌های پوریا صبوری, pouriya sabouri projects, نمونه کار برنامه‌نویس, نمونه کار فرانت‌اند, react projects, next.js projects, نمونه کار ریکت, پروژه‌های تمرینی برنامه‌نویسی, frontend portfolio, live projects, training projects, رزومه برنامه‌نویس, پورتفولیو توسعه‌دهنده وب"
        ogTitle="نمایش پروژه‌های پوریا صبوری | pouriya sabouri projects showcase"
        ogDescription="بیش از 20 پروژه حرفه‌ای و تمرینی در حوزه فرانت‌اند - مشاهده نمونه کارهای پوریا صبوری، توسعه‌دهنده React و Next.js | بیش از 10 پروژه زنده و 15 پروژه تمرینی"
        ogType="website"
        siteName="پوریا صبوری | نمونه کارهای برنامه‌نویسی"
        category="portfolio | projects | نمونه کار | پروژه‌ها"
      />
      <Box
        sx={{
          position: "relative",
          minHeight: "100svh",
          background: `
          radial-gradient(circle at 20% 50%, ${theme.palette.primary.dark}20 0%, transparent 40%),
          radial-gradient(circle at 80% 20%, ${theme.palette.secondary.dark}15 0%, transparent 40%),
          linear-gradient(135deg, ${theme.palette.background.default} 0%, ${theme.palette.background.lightBlue} 100%)
        `,
        }}
      >
        {/* Home Icon */}
        <IconButton
          onClick={() => navigate("/")}
          sx={{
            position: "fixed",
            top: "2rem",
            right: "2rem",
            zIndex: "100",
            border: `1px solid ${theme.palette.primary.dark}`,
            bgcolor: theme.palette.background.default,
            padding: ".5rem",
            ".MuiSvgIcon-root": {
              transition: "all .3s",
              fontSize: "1.2rem",
            },
            ":hover .MuiSvgIcon-root": {
              transform: "scale(1.1)",
              color: "white",
            },
          }}
        >
          <Home />
        </IconButton>
        <Container
          sx={{
            py: "3rem",
            display: "flex",
            flexDirection: "column",
          }}
          maxWidth={"exl"}
        >
          <Typography
            component={motion.h2}
            variants={nameVariants}
            initial="initial"
            animate="animate"
            variant="h4"
            sx={{ ...typoSx, textAlign: "center", mb: "2rem" }}
          >
            Projects
          </Typography>
          <Typography
            sx={{
              maxWidth: "70%",
              mx: "auto",
              mb: "2rem",
              textAlign: "center",
              color: "text.secondary",
            }}
          >
            A collection of my professional and training projects in frontend
            development. From real-time applications and e-commerce platforms to
            admin dashboards and corporate websites. Each project is built using
            React, Next.js, TypeScript, and modern frontend technologies. Here
            you can explore my live projects and training exercises.
          </Typography>
          {/* Tabs */}
          <Box sx={{ borderBottom: 1, borderColor: "divider", mb: 4 }}>
            <Tabs
              value={tabIndex}
              onChange={(e, newIndex) => setTabIndex(newIndex)}
              centered
              textColor="primary"
              indicatorColor="primary"
            >
              <Tab label="Live" icon={<RemoveRedEye />} iconPosition="start" />
              <Tab label="Training" icon={<Work />} iconPosition="start" />
            </Tabs>
          </Box>
          {/* Projects */}
          <Stack>
            <AnimatePresence mode="wait">
              {tabIndex == 0 ? (
                <motion.div
                  key={"liveItems"}
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  exit={{ opacity: 0 }}
                >
                  <Grid container direction={"row"}>
                    {LiveItems}
                  </Grid>
                </motion.div>
              ) : (
                <motion.div
                  key={"trainItems"}
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  exit={{ opacity: 0 }}
                >
                  <Grid container direction={"row"}>
                    {trainItems}
                  </Grid>
                </motion.div>
              )}
            </AnimatePresence>
          </Stack>
        </Container>
      </Box>
    </>
  );
}
